import clsx from 'clsx';
import {
  Children,
  forwardRef,
  isValidElement,
  type PropsWithChildren,
  type ReactElement,
  type ReactNode,
  useImperativeHandle,
  useMemo,
  useRef,
} from 'react';
import { useIntl } from 'react-intl';

import type { BaseInputProps } from './base-input.types.js';
import * as styles from './BaseInput.sty.js';
import { BaseInputButton } from './BaseInputButton.js';
import {
  BaseInputPrefix,
  BaseInputReservedSuffix,
  BaseInputSuffix,
} from './BaseInputContent.js';
import { BaseInputContext } from './contexts/BaseInputContext.js';
import { useFormControlState } from '../../core/hooks/useFormControlState.js';
import { useSplitProps } from '../../core/hooks/useSplitProps.js';
import { useFocusRing } from '../../core/styles/useFocusRing.js';
import { isSlot } from '../../core/utils/is-slot.js';
import { mergeProps as _mergeProps } from '../../core/utils/merge-props.js';
import { Divider } from '../../layouts/divider/Divider.js';
import { Flex } from '../../layouts/flex/Flex.js';
import { inputGroupClassName } from '../../layouts/input-group/InputGroup.sty.js';
import { InputGroup } from '../../layouts/input-group/InputGroup.js';
import { InternalBaseItem as BaseItem } from '../forms-core/components/form-field-messages/FormFieldMessageBaseItem.js';
import { useFormFieldMessagesContext } from '../forms-core/hooks/useFormFieldMessagesContext.js';
import { useFormFieldValidation } from '../forms-core/hooks/useFormFieldValidation.js';
import { useSyncedFormControlProps } from '../forms-core/hooks/useSyncedFormControlProps.js';
import { FormFieldMessagesAction } from '../forms-core/state/formfield-messages-state-reducer.js';
import { useAutofillEvent } from '../hooks/useAutofillEvent.js';
import { useInputHint } from '../hooks/useInputHint.js';
import type { FormControlRef } from '../shared-types.js';
import { getPlaceholderMessage } from './baseInputMessages.js';
import { ClearButton } from './ClearButton.js';

type SlotContent = {
  buttons: ReactElement[];
  rest: ReactNode[];
  props: Record<string, unknown>;
};

function getSlots(children: ReactNode) {
  const validSlots = Children.toArray(children).filter(
    isValidElement<PropsWithChildren>,
  );

  let prefix: SlotContent = { buttons: [], rest: [], props: {} };
  let suffix: SlotContent = { buttons: [], rest: [], props: {} };
  let reservedSuffix: SlotContent = { buttons: [], rest: [], props: {} };

  for (const slot of validSlots) {
    const buttons: SlotContent['buttons'] = [];
    const rest: SlotContent['rest'] = [];

    const slotChildren = Children.toArray(slot.props.children);

    for (const child of slotChildren) {
      if (isSlot(child, BaseInputButton)) {
        buttons.push(child);
      } else {
        rest.push(child);
      }
    }

    const { children: _children, ...slotProps } = slot.props;

    if (slot.type === BaseInputPrefix) {
      prefix = { buttons, rest, props: slotProps };
    }
    if (slot.type === BaseInputSuffix) {
      suffix = { buttons, rest, props: slotProps };
    }
    if (slot.type === BaseInputReservedSuffix) {
      reservedSuffix = { buttons, rest, props: slotProps };
    }
  }

  return { prefix, suffix, reservedSuffix };
}

const BaseInputRoot = /* @__PURE__ */ forwardRef<
  FormControlRef<HTMLDivElement>,
  BaseInputProps
>((props, forwardedRef) => {
  const intl = useIntl();

  const defaultPlaceholder = intl.formatMessage(
    getPlaceholderMessage(props.type),
  );

  const {
    children,
    id: propId,
    disabled: propDisabled,
    required: propRequired,
    'aria-disabled': ariaDisabledProp,
    variant = 'default',
    controlState,
    readOnly: propReadOnly,
    'data-testid': dataTestId,
    'data-dtrum-mask': dataDtrumMask,
    'data-dtrum-allow': dataDtrumAllow,
    'aria-label': ariaLabelProp,
    'aria-labelledby': ariaLabelledByProp,
    'aria-describedby': ariaDescribedByProp,
    'aria-details': ariaDetailsProp,
    className: consumerClassName,
    style: consumerStyle,
    // eslint-disable-next-line @typescript-eslint/no-deprecated
    onClear,
    type,
    placeholder = defaultPlaceholder,
    value,
    pattern,
    max,
    min,
    step,
    maxLength,
    minLength,
    ...remainingProps
  } = props;

  // assures that always an empty string is set
  const inputValue = value ?? '';

  const { disabled, required, id, ariaDisabled, readOnly } =
    useSyncedFormControlProps({
      propDisabled,
      propRequired,
      propId,
      propAriaDisabled: ariaDisabledProp,
      propReadOnly,
    });

  const disabledOrAriaDisabled = disabled || ariaDisabled || false;

  const [hasFormControlError, hint] = useFormControlState(controlState);
  // _useInputHint will be replaced with new validation concept. APPDEV-8298
  // eslint-disable-next-line @typescript-eslint/no-deprecated
  const { inputProps, hintProps } = useInputHint({
    hint,
    hasError: hasFormControlError,
  });

  const { state, dispatch } = useFormFieldMessagesContext();

  const hasError = hasFormControlError || state.showError;

  const { isAutoFilled, onAnimationStart } = useAutofillEvent();

  const inputRef = useRef<HTMLInputElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const { focusProps, focusClassName } = useFocusRing({
    color: hasError && !(disabled || ariaDisabled) ? 'critical' : 'neutral',
    ignoreModality: true,
    disabled,
  });

  const { onChange, onBlur, onInvalid, ariaProps } = useFormFieldValidation(
    inputRef,
    {
      required,
      pattern,
      max,
      min,
      step,
      maxLength,
      minLength,
      type,
      value: inputValue as string,
    },
    {
      'aria-label': ariaLabelProp,
      'aria-labelledby': ariaLabelledByProp,
      'aria-describedby': ariaDescribedByProp,
      'aria-details': ariaDetailsProp,
    },
  );
  const eventListener = { onChange, onBlur, onInvalid };

  useImperativeHandle(
    forwardedRef,
    (): FormControlRef<HTMLDivElement> => ({
      element: wrapperRef.current,
      inputRef: inputRef.current,
      focus() {
        inputRef.current?.focus();
      },
      validate() {
        inputRef.current?.checkValidity();
        dispatch?.({
          type: FormFieldMessagesAction.SETISTOUCHED,
          payload: { isTouched: true },
        });
      },
    }),
    [dispatch],
  );

  const context = useMemo(
    () => ({ variant, hasError, disabled, ariaDisabled }),
    [variant, hasError, disabled, ariaDisabled],
  );
  const slots = useMemo(() => getSlots(children), [children]);
  const hasInnerPrefix = slots.prefix.rest.length > 0;
  const hasInnerSuffix = slots.suffix.rest.length > 0;
  const hasInnerReservedSuffix = slots.reservedSuffix.rest.length > 0;
  const hasOnClear = onClear !== undefined;
  const showClearButton =
    hasOnClear && inputValue !== '' && !hasInnerReservedSuffix;

  const {
    matchedProps: dataAttributesProps,
    remainingProps: remainingInputProps,
  } = useSplitProps(remainingProps, [(key: string) => key.startsWith('data-')]);

  return (
    <Flex
      gap={4}
      flexDirection="column"
      data-testid={dataTestId}
      data-dtrum-mask={dataDtrumMask}
      data-dtrum-allow={dataDtrumAllow}
      ref={wrapperRef}
      className={consumerClassName}
      style={consumerStyle}
      {...dataAttributesProps}
    >
      <InputGroup
        style={{
          gridAutoColumns: `${'auto '.repeat(
            slots.prefix.buttons.length,
          )}1fr${' auto'.repeat(slots.suffix.buttons.length)}`,
        }}
        className={clsx(styles.wrapper, styles.variant[variant], {
          [styles.hasError]: hasError,
          [styles.disabled]: disabledOrAriaDisabled,
          [styles.readOnly]: readOnly,
        })}
      >
        <BaseInputContext.Provider value={context}>
          {slots.prefix.buttons}
          <div
            className={clsx(
              styles.container,
              inputGroupClassName,
              focusClassName,
              {
                [styles.isAutoFilled]: isAutoFilled,
                [`${styles.containerPadding.none}`]:
                  hasInnerReservedSuffix && hasInnerPrefix,
                [`${styles.containerPadding.rightNone}`]:
                  hasInnerReservedSuffix && !hasInnerPrefix,
                [`${styles.containerPadding.leftUnset}`]: hasInnerPrefix,
                [`${styles.containerPadding.rightUnset}`]: hasInnerSuffix,
              },
            )}
            onClick={() => inputRef.current?.focus()} // clicking on the icons should focus the input
          >
            {hasInnerPrefix && (
              <BaseInputPrefix {...slots.prefix.props}>
                {slots.prefix.rest}
              </BaseInputPrefix>
            )}

            <input
              id={id}
              ref={inputRef}
              required={required}
              disabled={!!disabled}
              aria-disabled={ariaDisabled}
              onAnimationStart={onAnimationStart}
              readOnly={readOnly}
              className={styles.input}
              placeholder={placeholder}
              type={type}
              value={inputValue}
              pattern={pattern}
              max={max}
              min={min}
              step={step}
              maxLength={maxLength}
              minLength={minLength}
              {..._mergeProps(
                remainingInputProps,
                focusProps,
                controlState
                  ? { 'aria-label': ariaLabelProp, ...inputProps }
                  : ariaProps,
                !controlState ? eventListener : {}, // escape hatch to not interfere with the old implementation
              )}
            />
            {hasInnerSuffix && (
              <BaseInputSuffix {...slots.suffix.props}>
                {slots.suffix.rest}
              </BaseInputSuffix>
            )}
            {!readOnly && (
              <>
                {hasInnerReservedSuffix ? (
                  <>
                    {hasInnerSuffix && (
                      <Divider
                        orientation="vertical"
                        className={styles.divider}
                      />
                    )}
                    {slots.reservedSuffix.rest}
                  </>
                ) : (
                  <>
                    {hasInnerSuffix && showClearButton && (
                      <Divider
                        orientation="vertical"
                        className={styles.divider}
                      />
                    )}
                    {showClearButton && <ClearButton onClear={onClear} />}
                  </>
                )}
              </>
            )}
          </div>
          {slots.suffix.buttons}
        </BaseInputContext.Provider>
      </InputGroup>
      {controlState && hint && (
        <BaseItem
          variant={hasError ? 'error' : 'hint'}
          disabled={disabledOrAriaDisabled}
          {...hintProps}
        >
          {hint}
        </BaseItem>
      )}
    </Flex>
  );
});

/**
 * Base component used internally for our input components.
 * @internal
 */
export const BaseInput = Object.assign(BaseInputRoot, {
  Prefix: BaseInputPrefix,
  Suffix: BaseInputSuffix,
  ReservedSuffix: BaseInputReservedSuffix,
  Button: BaseInputButton,
});

(BaseInput as typeof BaseInput & { displayName: string }).displayName =
  'BaseInput';
